let steps = [8000, 12000, 9000, 15000, 11000];
let goal = 10000;
// walk the list in order; find the FIRST day whose steps are >= goal
// print its 1-indexed day number (day 1 is the first day), then stop

reference.javascript:
let steps = [8000, 12000, 9000, 15000, 11000];
let goal = 10000;
let i = 0;
while (steps[i] < goal) {
  i = i + 1;
}
console.log(i + 1);
